const body = $input.first().json.body || $input.first().json;

const userId = body.user_id;
const orderId = body.order_id;
const eventType = body.event_type;
const trigger = body.trigger || body.status || '';

const relevantEvents = ['order.new', 'order.update.paymentStatus', 'order.update.shippingStatus'];
if (!relevantEvents.includes(eventType)) {
  return [{ json: { _skip: true, reason: `event ${eventType} diabaikan` } }];
}
if (!userId || !orderId) {
  throw new Error('Webhook payload missing user_id or order_id');
}

const APP_ID = 'Z1Ch4oa';
const APP_SECRET = 'o03Vk74kQIaN6aB5LNa3IgZDa3ltBwTxyAhQ4UB6vXUw';
const ts = Math.floor(Date.now() / 1000);
const hmacMessage = `${APP_ID}:${ts}:${APP_SECRET}`;

return [{ json: {
  app_id: APP_ID,
  api_secret: APP_SECRET,
  user_id: userId,
  order_id: orderId,
  event_type: eventType,
  trigger,
  ts,
  hmacMessage,
  target_url: `https://api.berdu.id/v0.0/order/detail?user_id=${userId}&order_id=${orderId}`
} }];

const d = $input.first().json;
const authHeader = `${d.app_id}.${d.ts}.${d.signature}`;
return [{ json: { ...d, authHeader } }];

const d = $input.first().json;
const order = d.body || d;

function normalizePhone(raw) {
  if (!raw) return null;
  return raw.toString().replace(/\s+/g, '').replace(/^\+/, '').replace(/^0/, '62');
}

function formatRupiah(num) {
  return 'Rp' + Number(num).toLocaleString('id-ID');
}

const addr = order.shipping_address || {};
const phone = normalizePhone(addr.phone);
const customerName = addr.firstName || 'Pelanggan';
const assignedStaff = order.assigned_to_staff;
const shippingCost = order.shipping_cost || 0;
const total = order.total || 0;
const paymentStatus = order.payment_status;

const productsSubtotal = (order.products || []).reduce((sum, p) => sum + (p.price * p.count), 0);
const productsList = (order.products || []).map(p => `${p.name} (${p.count}x)`).join(', ');

const shippingAddress = addr.address || '';
const shippingDistrict = addr.district || '';
const shippingCity = addr.city || '';

const staffMap = {
  'B-1apQSy': { senderName: 'CS Aisyah', sender: '6281385708799',  apiKey: 'kc_live_eepCPoHDjpF3AyPfX0_2MNDspKiyOcbBxEEeyWJQYNg', templateName: 'whatsapp_notif_order_aisyah' },
  'B-1CxSmL': { senderName: 'CS Risma',  sender: '6282321381742', apiKey: 'kc_live_vvgG_3JEVsqcsBY3KNakKDqd5CMPFxGuUvyMke5QWf8',  templateName: 'whatsapp_notif_order_risma' },
  // Lila (B-NCIXt), Azela (B-Z28TdYc): belum connect ke KirimChat, tambahkan setelah punya akun sendiri
};

const csConfig = staffMap[assignedStaff];
if (!csConfig) {
  return [{ json: { _skip: true, reason: `staff ${assignedStaff} tidak ada di mapping` } }];
}
if (!phone) {
  return [{ json: { _skip: true, reason: 'phone number tidak ditemukan di order' } }];
}

const webhookData = $('Extract Webhook Data').first().json;

const aiSalesAgentEnabled = csConfig.senderName === 'CS Aisyah';
const stateTrackingEnabled = ['CS Aisyah', 'CS Risma'].includes(csConfig.senderName);

if (phone && csConfig && stateTrackingEnabled) {
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://n8n.miqra.dev/webhook/conversation-state',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        action: 'set_order',
        phone,
        csName: csConfig.senderName,
        productName: (order.products || [])[0]?.name || '',
        products: productsList,
        productsSubtotal: formatRupiah(productsSubtotal),
        shippingCost: formatRupiah(shippingCost),
        total: formatRupiah(total),
        customerName,
        shippingAddress,
        shippingDistrict,
        shippingCity,
        order_id: webhookData.order_id,
      }),
    });
  } catch (_) {}
}

// ============================================================
// TEMPLATE VARIABLE ORDER - JANGAN UBAH URUTAN INI!
// Template Meta: 'whatsapp_notif_order_aisyah' dan 'whatsapp_notif_order_risma'
// Format template:
//   'Saya {{2}} dari Pustaka Islam'
//   'Produk: {{3}}', 'Harga: {{4}}', 'Ongkir: {{5}}', 'Total: {{6}}'
//   'Dikirim ke: {{1}} | {{7}}'
//   '{{8}}, {{9}}, {{10}}'
// ============================================================
const templateParams = [
  customerName,                   // {{1}} nama penerima
  csConfig.senderName,            // {{2}} nama CS
  productsList,                   // {{3}} Produk
  formatRupiah(productsSubtotal), // {{4}} Harga
  formatRupiah(shippingCost),     // {{5}} Ongkir
  formatRupiah(total),            // {{6}} Total
  phone,                          // {{7}} HP penerima
  shippingAddress,                // {{8}} alamat
  shippingDistrict,               // {{9}} kecamatan
  shippingCity,                   // {{10}} kota
];

// Build KirimChat request body in Code node (native JS - no expression engine quirks)
const kirimChatBody = {
  phone_number: phone,
  channel: 'whatsapp',
  message_type: 'template',
  template: {
    name: csConfig.templateName,
    language: { code: 'id' },
    components: [{
      type: 'body',
      parameters: templateParams.map(text => ({ type: 'text', text: String(text) })),
    }],
  },
};

return [{ json: {
  phone,
  customerName,
  assignedStaff,
  csConfig,
  aiSalesAgentEnabled,
  total: formatRupiah(total),
  productsSubtotal: formatRupiah(productsSubtotal),
  shippingCost: formatRupiah(shippingCost),
  paymentStatus,
  products: productsList,
  shippingAddress,
  shippingDistrict,
  shippingCity,
  templateParams,
  orderUrl: order.url || '',
  event_type: webhookData.event_type,
  trigger: webhookData.trigger,
  order_id: webhookData.order_id,
  kirimChatBody,
} }];

const result = $input.first().json;
console.log('Done:', JSON.stringify({ status: result.statusCode || 'skipped' }));
return [{ json: { logged: true, ts: new Date().toISOString() } }];
